        configureSecureDocumentBuilderFactory(dbf);

        try {
            // Parse the XML file into a Document
            DocumentBuilder db = dbf.newDocumentBuilder();
            Document sourceDocument = db.parse(new File(configPath));

            // Create identity transformer with secure configuration
            TransformerFactory transformerFactory = TransformerFactory.newInstance();
            configureSecureTransformerFactory(transformerFactory);

            Transformer transformer = transformerFactory.newTransformer();

            // Perform identity transform
            DOMResult domResult = new DOMResult();
            javax.xml.transform.dom.DOMSource domSource = 
                new javax.xml.transform.dom.DOMSource(sourceDocument);
            transformer.transform(domSource, domResult);

            // Return the transformed document
            return (Document) domResult.getNode();

        } catch (ParserConfigurationException | SAXException e) {
            // Wrap parsing exceptions in TransformerException for consistency
            throw new TransformerException("Failed to parse XML configuration: " + e.getMessage(), e);
        }
    }

    /**
     * Configures DocumentBuilderFactory with security settings to prevent XXE attacks.
     *
     * @param dbf DocumentBuilderFactory to configure
     */
    private void configureSecureDocumentBuilderFactory(DocumentBuilderFactory dbf) {
        try {
            // Disable DTDs and external entities
            dbf.setFeature(XMLConstants.FEATURE_SECURE_PROCESSING, true);
            dbf.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true);
            dbf.setFeature("http://xml.org/sax/features/external-general-entities", false);
            dbf.setFeature("http://xml.org/sax/features/external-parameter-entities", false);
            dbf.setXIncludeAware(false);
            dbf.setExpandEntityReferences(false);
        } catch (ParserConfigurationException e) {
            throw new RuntimeException("Failed to configure secure DocumentBuilderFactory", e);
        }
    }

    /**
     * Configures TransformerFactory with security settings to prevent XXE attacks.
     *
     * @param transformerFactory TransformerFactory to configure
     */
    private void configureSecureTransformerFactory(TransformerFactory transformerFactory) {
        try {
            // Enable secure processing
            transformerFactory.setFeature(XMLConstants.FEATURE_SECURE_PROCESSING, true);

            // Disable external DTDs and stylesheets
            transformerFactory.setAttribute(XMLConstants.ACCESS_EXTERNAL_DTD, "");
            transformerFactory.setAttribute(XMLConstants.ACCESS_EXTERNAL_STYLESHEET, "");
        } catch (Exception e) {
            throw new RuntimeException("Failed to configure secure TransformerFactory", e);
        }
    }
}
